	('5c807de7-b4ff-45e3-a293-43e72b0e5bb5', 'Pastels', '(Stuffed Fried Pastries) Crispy fried pastries filled with fish and veggies', 10.99, 'appetizer', 'https://onlybyland.com/senegalese-food-dishes/', false, '2025-11-26 15:06:10.582359+00', false),
	('ba5d3625-cc0e-4424-8617-b3dff36f92dd', 'BBQ Chicken Pizza', 'Tangy BBQ sauce with grilled chicken and onions.', 15.99, 'Pizza', 'https://example.com/images/bbq_chicken.jpg', false, '2025-10-25 18:15:47.367766+00', false),
	('e757e570-9537-47d3-bf94-9c1f7d1eddaf', 'Bassi Salte', '(Millet Couscous) With meatballs, sweet potatoes, cabbage, and carrots in a rich meat and veggie sauce', 13.99, 'main', 'https://afrifoodnetwork.com/wp-content/uploads/2022/07/bassi-salte.jpg', true, '2025-11-26 15:06:10.582359+00', false),
	('2471aed6-68c2-4627-8c43-78fa44101bbb', 'Senegalese Paella', '(Fusion Dish) Saffron-infused rice with marinated chicken or fish, vegetables, and mango salsa', 14.99, 'main', 'https://cdn.africanvibes.com/wp-content/uploads/2024/08/07154608/Moroccan-Paella-826x1024.jpg', true, '2025-11-26 15:06:10.582359+00', false),
	('228f4d89-2a7d-4e1d-bd9d-aadd14928b14', 'Cheeseburger', 'Juicy beef patty with cheese, lettuce, and tomato.', 11.99, 'Burger', 'https://example.com/images/cheeseburger.jpg', false, '2025-10-25 18:15:47.367766+00', false),
	('45ef8a85-b61b-44e4-b496-ac9688c48fd4', 'Dibi', '(Grilled Lamb) Served with marinated onions, plantains, fries, salad, and bread', 13.99, 'main', 'https://s3-media0.fl.yelpcdn.com/bphoto/lAUAy74dkupkfCuhwGqwMA/o.jpg', true, '2025-11-26 15:06:10.582359+00', false),
	('7509d0a8-748f-421b-baa8-a03f8a409ece', 'Poulet et Poisson Braisés', '(Grilled Chicken or Fish) Served with rice or Attieke, plantains, onion sauce, fries, or salad', 14.99, 'main', 'https://i.ytimg.com/vi/c5-x8e4g_P0/hq720.jpg?sqp=-oaymwEhCK4FEIIDSFryq4qpAxMIARUAAAAAGAElAADIQj0AgKJD&rs=AOn4CLBboD3_pPZYRQ99BMLkGzdAWK1FBw', true, '2025-11-26 15:06:10.582359+00', false),
