	('d32d1185-b496-4d78-b741-ae35ff7c2734', 'Thiere', '(Millet Couscous) Served with tomato stew, tender meat, and vegetables', 14.99, 'main', 'https://m.media-amazon.com/images/I/71Eez1ABVLL._AC_UF350,350_QL80_.jpg', true, '2025-11-26 15:06:10.582359+00', true),
	('d6c135aa-ba08-4008-b12a-4a14dc3ee8df', 'Ngalakh', '(Millet Porridge) Creamy and sweet porridge made with millet and peanut butter served cold', 8.99, 'dessert', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTd1jDXJUjxzZdQAQ4FmHNi0l9FTSGhV4Afeg&s', true, '2025-11-26 15:06:10.582359+00', false),
	('e3cdbf0d-3e25-47b6-9089-d6565db892c9', 'Ndambe', '(Spicy Bean Sandwich) Comes with meat and boiled eggs served on a French baguette', 12.99, 'main', 'https://www.tastingtable.com/img/gallery/senegals-bean-sandwich-is-a-savory-way-to-begin-the-day/intro-1701479233.jpg', true, '2025-11-26 15:06:10.582359+00', false),
	('04e16750-7469-4073-ba30-34f886f16ca3', 'Thiacry', '(Sweet Couscous Dessert) Sweet, creamy dessert made with couscous and peanut sauce served cold', 8.99, 'dessert', 'https://fourcarrockcourt.com/wp-content/uploads/2024/08/Thiakry-copy-18.jpg', true, '2025-11-26 15:06:10.582359+00', false),
	('b628a1e8-9efc-4041-a169-8bfab8200a04', 'Efo Riro', '(Nigerian Spinach Stew) Spinach, pepper mix, palm oil, and meat or fish cooked with spices, served with swallow or rice', 14.99, 'main', 'https://lowcarbafrica.com/wp-content/uploads/2019/08/Efo-Riro-IG-1.jpg', true, '2025-11-26 15:06:10.582359+00', false),
	('63ce2e8b-58a8-4ae8-99ae-0bc8065b38c2', 'Bouye', '(Baobab Juice) Drink from Senegal made from baobab fruit pulp, powdered milk, and concentrated milk', 5.99, 'juice', 'https://tropiki.no/wp-content/uploads/2025/08/Baobab-Juice_-copy-5-370x250.jpg', true, '2025-11-26 15:06:10.582359+00', false),
	('12f51ef7-dee7-4b0b-b5a3-db2f38c9838f', 'Bissap', '(Hibiscus Drink) Refreshing and sweet drink made with hibiscus flowers', 5.99, 'juice', 'https://fourcarrockcourt.com/wp-content/uploads/2024/08/Bissap_-copy.jpg', true, '2025-11-26 15:06:10.582359+00', false),
	('a69c439d-bd36-490d-b9d5-6eca7f3f1cb0', 'Fataya', '(Senegalese Meat Pies) Flaky pastry filled with spiced meat, served with a sweet and sour tomato sauce', 10.99, 'appetizer', 'https://i.pinimg.com/736x/48/f4/bc/48f4bca31ba62ce5ecd15dac2a7458e1.jpg', true, '2025-11-26 15:06:10.582359+00', false),
	('65977cd6-470d-47cc-9710-35cd6dfb95a4', 'Akara', '(Cowpea Donuts) Fried bean cakes served with a spicy dipping sauce', 10.99, 'appetizer', 'https://www.196flavors.com/wp-content/uploads/2016/02/Akaras-4-FP.jpg', true, '2025-11-26 15:06:10.582359+00', false),
	('202fbd73-bed7-4a6b-a954-7fb8fc8b5393', 'Thieboudienne', '(National Dish of Senegal) Hearty fish and rice stew with vegetables and spices', 14.99, 'main', 'https://www.foodandwine.com/thmb/bz5Yc9G9oetSrsgciYp_j5iIO3E=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/Thieboudienne-Senegalese-Jollof-Rice-and-Fish-FT-MAG-RECIPE-0924-722fd4dd3a2b490fb2fbbab3a70a55f6.jpg', true, '2025-11-26 15:06:10.582359+00', false),
