	('10718246-144b-4678-ae5f-8a561f1bace4', 'Domoda', '(Stew with Tomato Paste and Lemon Sauce) Hearty stew made with fragrant lemon sauce, often with beef, lamb, or fish', 14.99, 'main', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQfptvYje1HPowrCSHou60mOtfFTWVuw7xOUA&s', true, '2025-11-26 15:06:10.582359+00', false),
